def delete_project(actor, project_id, correlation_id):
    if 'admin' not in actor.roles:
        logger.info('audit', audit=True, control='access.authz', action='project.delete', actor=actor.id, target={'type':'project','id':project_id}, outcome='denied', reason='insufficient_role', ts=now(), correlation_id=correlation_id)
        raise Forbidden()
    repo.delete_project(project_id)
    logger.info('audit', audit=True, control='access.authz', action='project.delete', actor=actor.id, target={'type':'project','id':project_id}, outcome='allowed', ts=now(), correlation_id=correlation_id)

priv-grant-role:
def grant_role(actor_id, user_id, role, correlation_id):
    try:
        repo.grant(user_id, role)
    except Exception as e:
        logger.info('audit', audit=True, control='access.privileged', action='role.grant', actor=actor_id, target={'type':'user','id':user_id}, outcome='failure', reason=type(e).__name__, ts=now(), correlation_id=correlation_id)
        raise
    logger.info('audit', audit=True, control='access.privileged', action='role.grant', actor=actor_id, target={'type':'user','id':user_id}, outcome='success', ts=now(), correlation_id=correlation_id)

